"use client";

// Stone-effect render wizard — client-side interactive.
//
// Steps: 1) Guide (Philip's drawing) → 2) Postcode →
// 3) Elevations (A/B/C + openings dropdown) → 4) Result
//
// Estimate is generated by POSTing to /api/plan/stone-effect-render/estimate
// which does the cited-rate math server-side (rates never leak to the
// browser as bare numbers; every render includes citations).

import { useMemo, useState } from "react";
import Link from "next/link";
import {
  ArrowRight, ArrowLeft, Loader2, Info, ExternalLink,
  Plus, Minus, Trash2, AlertTriangle, Sparkles, MapPin,
  Home as HomeIcon, ScrollText, BookOpen
} from "lucide-react";

// ─── Types matching the API response ──────────────────────────────

type Opening = {
  type_slug:  string;
  label:      string;
  width_m:    number;
  height_m:   number;
  count:      number;
};
type Elevation = {
  name:        string;
  width_m:     number;
  height_m:    number;
  gable_rise_m: number;    // 0 if no gable
  openings:    Opening[];
};

type EstimateLine = {
  line_item_slug: string;
  display_name:   string;
  quantity:       number;
  unit:           string;
  low_pence:      number;
  high_pence:     number;
  citation_text:  string;
  source_url:     string;
  excludes_notes: string | null;
};

type EstimateResult = {
  ok:                  boolean;
  total_low_pence:     number;
  total_high_pence:    number;
  render_area_m2:      number;
  region_display:      string | null;
  region_multiplier:   number;
  region_source_url:   string | null;
  lines:               EstimateLine[];
  extras_excluded:     string[];
  confidence:          "high" | "moderate" | "low";
  finish_display:      string;
};

