// ─── Wizard state ─────────────────────────────────────────────────

type Step = "guide" | "postcode" | "walls" | "generating" | "result";

export function WizardClient() {
  const [step, setStep]                 = useState<Step>("guide");
  const [postcode, setPostcode]         = useState("");
  const [housePreset, setHousePreset]   = useState<keyof typeof HOUSE_PRESETS>("semi-detached-3bed");
  const [finish, setFinish]             = useState("stone-effect");
  const [elevations, setElevations]     = useState<Elevation[]>(HOUSE_PRESETS["semi-detached-3bed"].elevations);
  const [busy, setBusy]                 = useState(false);
  const [error, setError]               = useState<string | null>(null);
  const [result, setResult]             = useState<EstimateResult | null>(null);

  function pickPreset(key: keyof typeof HOUSE_PRESETS) {
    setHousePreset(key);
    // Deep clone the preset so edits don't mutate it
    setElevations(JSON.parse(JSON.stringify(HOUSE_PRESETS[key].elevations)));
  }

  async function generate() {
    setBusy(true); setError(null); setStep("generating");
    try {
      const res  = await fetch("/api/plan/stone-effect-render/estimate", {
        method:  "POST",
        headers: { "Content-Type": "application/json" },
        body:    JSON.stringify({ postcode, finish, elevations })
      });
      const json = await res.json();
      if (!json.ok) { setError(json.error ?? "Something went wrong"); setStep("walls"); setBusy(false); return; }
      setResult(json);
      setStep("result");
    } catch (e) {
      setError(e instanceof Error ? e.message : String(e));
      setStep("walls");
    } finally {
      setBusy(false);
    }
  }

  return (
    <>
      {/* Progress crumbs */}
      <ol className="mb-4 flex items-center gap-1 text-[10.5px] font-black uppercase tracking-wider text-neutral-500">
        {["guide","postcode","walls","result"].map((s, i) => (
          <li key={s} className="flex items-center gap-1">
            <span className={step === s ? "text-neutral-900" : ""}>
              {i + 1}. {s === "guide" ? "How to measure" : s === "postcode" ? "Postcode" : s === "walls" ? "Wall details" : "Estimate"}
            </span>
            {i < 3 && <span aria-hidden>→</span>}
          </li>
        ))}
      </ol>

      {step === "guide"     && <GuideStep     onNext={() => setStep("postcode")}/>}
      {step === "postcode"  && <PostcodeStep  postcode={postcode} setPostcode={setPostcode} housePreset={housePreset} pickPreset={pickPreset} onBack={() => setStep("guide")} onNext={() => setStep("walls")}/>}
      {step === "walls"     && <WallsStep     elevations={elevations} setElevations={setElevations} finish={finish} setFinish={setFinish} error={error} onBack={() => setStep("postcode")} onGenerate={generate} busy={busy}/>}
      {step === "generating"&& <GeneratingStep/>}
      {step === "result"    && result && <ResultStep result={result} onBack={() => setStep("walls")} onRestart={() => { setStep("guide"); setResult(null); }}/>}
    </>
  );
}

